2）nfs4_closedatastruct nfs4_closedata &#123;	struct inode *inode;          /* 对应的inode */	struct nfs4_state *state;     /* 对应的state */	struct nfs_closeargs arg;     /* close请求的参数 */	struct nfs_closeres res;      /* close请求的结果 */	struct &#123;		struct nfs4_layoutreturn_args arg;		struct nfs4_layoutreturn_res res;		struct nfs4_xdr_opaque_data ld_private;		u32 roc_barrier;		bool roc;	&#125; lr;	struct nfs_fattr fattr;       /* nfs文件属性 */	unsigned long timestamp;      /* 时间戳 */&#125;;

__nfs4_close四个参数，state是open操作创建的nfs4_state结构，fmode表示关闭的访问模式，wait表示是同步还是异步操作。nfs4_state结构中的n_rdonly、n_wronly、n_rdwr分别表示这个用户以只读权限、只写权限、读写权限打开文件的次数，每执行一次close操作都需要减少相应权限的计数，通常情况下，当n_rdonly和n_rdwr都减到0时就可以向服务器发起请求释放读权限，当n_wronly和n_rdwr都减到0时就可以向服务器发起请求释放写权限。但是涉及到delegation就会有一些特殊的情况，当一个客户端的两个用户打开同一个文件，第一个用户如果被分配了delegation，第二个用户就可以不使用open请求就直接打开该文件，而在关闭时自然也不需要发送close请求。
如果不需要发送close请求，则只需要调用nfs4_put_open_state函数清除相应的nfs4_state数据和调用nfs4_put_state_owner函数将对应的state_owner从LRU链表中释放。如果需要发送close请求，则调用nfs4_do_close发送close请求报文。
